+    local procedure SplitAndInsertInventoryProfileForMultipleBindings(var InventoryProfile: Record "Inventory Profile"; var ProdOrderLine: Record "Prod. Order Line"; ToDate: Date; var LineNo: Integer): Boolean
+    var
+        ReservEntry: Record "Reservation Entry";
+        OppositeReservEntry: Record "Reservation Entry";
+        SplitInventoryProfile: Record "Inventory Profile";
+        TotalOrderToOrderQty: Decimal;
+        IsFirst: Boolean;
+    begin
+        if InventoryProfile.Binding <> InventoryProfile.Binding::"Order-to-Order" then
+            exit(false);
+
+        if not InventoryProfile.IsSupply then
+            exit(false);
+
+        ProdOrderLine.SetReservationFilters(ReservEntry);
+        ReservEntry.SetRange(Positive, true);
+        ReservEntry.SetRange("Reservation Status", ReservEntry."Reservation Status"::Reservation);
+        ReservEntry.SetRange(Binding, ReservEntry.Binding::"Order-to-Order");
+
+        if not ReservEntry.FindSet() then
+            exit(false);
+
+        if ReservEntry.Count() <= 1 then
+            exit(false);
+
+        repeat
+            TotalOrderToOrderQty += ReservEntry."Quantity (Base)";
+        until ReservEntry.Next() = 0;
+
+        // Only split when all remaining quantity is covered by Order-to-Order bindings.
+        // This ensures no untracked quantity is lost when not splitting.
+        if TotalOrderToOrderQty <> InventoryProfile."Untracked Quantity" then
+            exit(false);
+
+        // Create one supply inventory profile per Order-to-Order binding so that
+        // each demand's Primary Order can be matched to its own dedicated supply profile.
+        IsFirst := true;
+        ReservEntry.FindSet();
+        repeat
+            OppositeReservEntry.Get(ReservEntry."Entry No.", not ReservEntry.Positive);
+
+            SplitInventoryProfile := InventoryProfile;
+            if not IsFirst then begin
+                LineNo += 1;
+                SplitInventoryProfile."Line No." := LineNo;
+            end;
+
+            SplitInventoryProfile."Quantity (Base)" := ReservEntry."Quantity (Base)";
+            SplitInventoryProfile.Quantity := ReservEntry.Quantity;
+            SplitInventoryProfile."Remaining Quantity (Base)" := ReservEntry."Quantity (Base)";
+            SplitInventoryProfile."Remaining Quantity" := ReservEntry.Quantity;
+            SplitInventoryProfile."Untracked Quantity" := ReservEntry."Quantity (Base)";
+            SplitInventoryProfile."Min. Quantity" := 0;
+            SplitInventoryProfile."Finished Quantity" := 0;
+
+            SplitInventoryProfile."Primary Order Type" := OppositeReservEntry."Source Type";
+            SplitInventoryProfile."Primary Order Status" := OppositeReservEntry."Source Subtype";
+            SplitInventoryProfile."Primary Order No." := OppositeReservEntry."Source ID";
+            if OppositeReservEntry."Source Type" <> Database::"Prod. Order Component" then
+                SplitInventoryProfile."Primary Order Line" := OppositeReservEntry."Source Ref. No."
+            else
+                SplitInventoryProfile."Primary Order Line" := OppositeReservEntry."Source Prod. Order Line";
+
+            SplitInventoryProfile.InsertSupplyInvtProfile(ToDate);
+            IsFirst := false;
+        until ReservEntry.Next() = 0;
+
+        exit(true);
+    end;
